const raw = $input.first().json;
const text = (raw.content?.[0]?.text || '').trim();

if (!text) throw new Error('Empty response from Claude');

const fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
const clean = fenceMatch ? fenceMatch[1].trim() : text;
const start = clean.indexOf('{');

if (start === -1) {
  throw new Error('No JSON object found. Tail: ...' + text.slice(-200));
}

let jsonStr = clean.slice(start);

// Detect truncation and repair by closing open strings and brackets
function repairTruncatedJson(s) {
  const stack = [];
  let inStr = false, esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { esc = false; continue; }
    if (c === '\\' && inStr) { esc = true; continue; }
    if (c === '"') { inStr = !inStr; continue; }
    if (!inStr) {
      if (c === '{' || c === '[') stack.push(c);
      else if (c === '}' || c === ']') stack.pop();
    }
  }
  if (stack.length === 0 && !inStr) return { repaired: s, truncated: false };
  let repaired = s;
  if (inStr) repaired += '"';
  repaired = repaired.replace(/,\s*$/, '');
  if (/:\s*$/.test(repaired)) repaired += 'null';
  while (stack.length > 0) {
    repaired += stack.pop() === '{' ? '}' : ']';
  }
  return { repaired, truncated: true };
}

const { repaired, truncated } = repairTruncatedJson(jsonStr);
if (truncated) jsonStr = repaired;

function parseWithFixes(s) {
  try { return JSON.parse(s); } catch (_) {}
  try {
    const fixed = s.replace(/^\s*\/\/.*$/gm, '').replace(/,(\s*[}\]])/g, '$1');
    return JSON.parse(fixed);
  } catch (_) {}
  try {
    let sanitized = '';
    let inString = false, escaped = false;
    for (let i = 0; i < s.length; i++) {
      const c = s[i];
      if (escaped) { sanitized += c; escaped = false; }
      else if (c === '\\' && inString) { sanitized += c; escaped = true; }
      else if (c === '"') { sanitized += c; inString = !inString; }
      else if (inString && c === '\n') { sanitized += '\\n'; }
      else if (inString && c === '\r') { /* skip */ }
      else if (inString && c === '\t') { sanitized += '\\t'; }
      else { sanitized += c; }
    }
    return JSON.parse(sanitized);
  } catch (e) {
    throw new Error('All parse attempts failed: ' + e.message + '. Last 300 chars: ...' + s.slice(-300));
  }
}

const parsed = parseWithFixes(jsonStr);
parsed._truncated = truncated;
return { json: JSON.parse(JSON.stringify(parsed)) };
